      const playerGoals = isHome ? lastMatch.homeScore : lastMatch.awayScore;
      const rivalGoals = isHome ? lastMatch.awayScore : lastMatch.homeScore;
      
      // Only allow replay on a loss
      if (playerGoals >= rivalGoals) return state;
      
