          const drawn = goals === against ? 1 : 0;
          const lost = goals < against ? 1 : 0;
          const pts = won * 3 + drawn;
          const newGF = Math.max(0, t.goalsFor - goals);
          const newGA = Math.max(0, t.goalsAgainst - against);
